PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  VALUES ?championship {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?game wdt:P361 ?championship ; wdt:P1535 wd:Q213959 ; wdt:P1083 ?attendance .
  FILTER(xsd:integer(?attendance) > 0)
}
LIMIT 10

args.sparql:
SELECT (MAX(?attendance) AS ?maxAttendance) WHERE {
  VALUES ?series {
    wd:Q56692089 # 2018 World Series
    wd:Q14870260 # 2013 ALCS
    wd:Q3511178  # 1975 ALCS
  }
  ?series p:P580/ps:P580 ?start;
          p:P582/ps:P582 ?end.
  ?game wdt:P31/wdt:P279* wd:Q154949; 
        wdt:P641 wd:Q3305213;
        wdt:P585 ?date;
        wdt:P710 wd:Q213959;
        wdt:P1083 ?attendance.
  FILTER (?date >= ?start && ?date <= ?end)
}

SELECT (MAX(?attendance) AS ?maxAttendance)
WHERE {
  VALUES ?series {
    wd:Q56692089
    wd:Q14870260
    wd:Q3511178
  }
  ?series wdt:P1344 wd:Q213959, ?opponent.
  ?opponent wdt:P31/wdt:P279* wd:Q317132.
  ?game wdt:P710 wd:Q213959;
        wdt:P710 ?opponent;
        wdt:P641 wd:Q3305213;
        wdt:P580|wdt:P585 ?date;
        wdt:P1083 ?attendance.
  ?series p:P580/ps:P580 ?seriesStart.
  FILTER(YEAR(?date) = YEAR(?seriesStart))
}
ORDER BY DESC(?attendance)
LIMIT 1

SELECT (MAX(?attendance) AS ?maxAttendance)
